    86	fn waitForNotification(fd: std.c.fd_t, timeout_ms: i32) !bool {
    87	    var pfd = [_]std.c.pollfd{
    88	        .{ .fd = fd, .events = POLLIN, .revents = 0 },
    89	    };
    90	    const rc = std.c.poll(&pfd, pfd.len, timeout_ms);
    91	    try std.testing.expect(rc >= 0);
    92	    return rc == 1 and (pfd[0].revents & POLLIN) != 0;
    93	}
